#define DT 0.002f
#define DXY 20.0f
#define HALF_LENGTH 1

#define MIN(a, b) (a) < (b) ? (a) : (b)

void usage(std::string programName) {
  std::cout << " Incorrect parameters " << std::endl;
  std::cout << " Usage: ";
