  memcpy(d_in, buffer, sizeof(float)*Lx*Ly);

  double t0;


  #pragma omp target data map(to: d_in[0:Lx*Ly]) map(alloc: d_out[0:Lx*Ly])
  {
    t0 = stop_watch(0);
